/**
 * @param {string} s
 * @return {number}
 */
function solve(s) {
    const n = s.length;
    let maxLen = 0;

    // Helper function to find the longest balanced subarray in a given string t
    // A subarray is balanced if count('0') == count('1')
    function longestBalancedSubarray(t) {
        const m = t.length;
        if (m === 0) return 0;

        // Use prefix sums (balance: count('1') - count('0'))
        const balance = new Array(m + 1).fill(0);
        for (let i = 0; i < m; i++) {
            balance[i + 1] = balance[i] + (t[i] === '1' ? 1 : -1);
        }

        // Map to store the first index where a certain balance was achieved
        const firstOccurrence = new Map();
        firstOccurrence.set(0, -1); // Balance 0 is achieved before index 0

        let currentMaxLen = 0;

        for (let j = 0; j < m; j++) {
            // balance[j+1] is the balance up to index j
            const currentBalance = balance[j + 1];

            if (firstOccurrence.has(currentBalance)) {
                // A balanced subarray exists between firstOccurrence.get(currentBalance) + 1 and j
                const startIdx = firstOccurrence.get(currentBalance);
                const length = j - startIdx;
                currentMaxLen = Math.max(currentMaxLen, length);
            } else {
                // Record the first time this balance is seen
                firstOccurrence.set(currentBalance, j);
            }
        }
        return currentMaxLen;
    }

    // Case 1: No swap (0 swaps)
    maxLen = longestBalancedSubarray(s);

    // Case 2: One swap
    // Iterate over all possible pairs of indices (i, j) to swap
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            // Optimization: only swap if the characters are different
            if (s[i] === s[j]) continue;

            // Create the new string t by swapping s[i] and s[j]
            let chars = s.split('');
            [chars[i], chars[j]] = [chars[j], chars[i]];
            const t = chars.join('');

            // Find the longest balanced subarray in t
            const currentLen = longestBalancedSubarray(t);
            maxLen = Math.max(maxLen, currentLen);
        }
    }

