object Solution {
  /**
   * Helper function to find the longest balanced subarray in a given string t.
   * A subarray is balanced if count('0') == count('1').
   * @param t The binary string.
   * @return The maximum length of a balanced subarray.
   */
  private def longestBalancedSubarray(t: String): Int = {
    val m = t.length
    if (m == 0) return 0

    // Use a Map to store the first index where a certain balance was achieved.
    // Balance is defined as count('1') - count('0').
    val firstOccurrence = scala.collection.mutable.Map[Int, Int]()
    firstOccurrence.put(0, -1) // Balance 0 is achieved before index 0

    var currentMaxLen = 0
    var currentBalance = 0

    for (j <- 0 until m) {
      // Update balance: +1 for '1', -1 for '0'
      if (t(j) == '1') {
        currentBalance += 1
      } else { // t(j) == '0'
        currentBalance -= 1
      }

      if (firstOccurrence.contains(currentBalance)) {
        // A balanced subarray exists between firstOccurrence.get(currentBalance) + 1 and j
        val startIdx = firstOccurrence(currentBalance)
        val length = j - startIdx
        currentMaxLen = Math.max(currentMaxLen, length)
      } else {
        // Record the first time this balance is seen
        firstOccurrence.put(currentBalance, j)
      }
    }
    currentMaxLen
  }

  /**
   * Solves the problem: find the maximum length of a balanced subarray after at most one swap.
   * @param s The binary string.
   * @return The maximum length.
   */
  def solve(s: String): Int = {
    val n = s.length
    var maxLen = 0

    // Case 1: No swap (0 swaps)
    maxLen = Math.max(maxLen, longestBalancedSubarray(s))

    // Case 2: One swap
    // Iterate over all possible pairs of indices (i, j) to swap
    for (i <- 0 until n) {
      for (j <- i + 1 until n) {
        // Optimization: only swap if the characters are different
        if (s(i) == s(j)) continue

        // Create the new string t by swapping s[i] and s[j]
        val chars = s.toCharArray.toSeq
        // Perform swap
        chars :+= (chars.updated(i, s(j)).updated(j, s(i)))
        val t = chars.mkString

        // Find the longest balanced subarray in t
        val currentLen = longestBalancedSubarray(t)
        maxLen = Math.max(maxLen, currentLen)
      }
    }

    maxLen
  }
}
